### 代码1：逐行读取 JSONL → 调用 SGLang（base64 图）→ 保存为一个 JSON（list）

保存为 `run_sglang_and_dump_json.py`

```python
import base64
import json
import mimetypes
import requests
from pathlib import Path
from string import Template
from typing import Any, Dict, List, Optional

# ========== 配置 ==========
JSONL_PATH = Path(
    "/mnt/shared-storage-user/songdemin/user/wangrui/datasets/mlm-project/pdf-subject-image-recall/query-sfe-pdf-subjects-image-recall-260201/top-1000-dedup-and-join-jsonl-uniq-image/v1/P~Chemistry~chemistry~251204_delivery_allpdfs_chemistry_finalize_part1-Engineering~1.0.0~0.0/part-69800baec1c4-000074.jsonl"
)
PROMPT_PATH = Path("qa_prompt2.txt")

IMAGE_ROOT = Path(
    "/mnt/shared-storage-user/songdemin/user/wangrui/codes/mlm_retrive_recall/mRetry/sfe-caption-recall-images-uniq"
)

OUT_JSON_PATH = Path("sglang_outputs.json")  # 存一个 json(list)

SGLANG_URL = "http://100.101.120.214:30000/v1/chat/completions"
TEMP = 0.6
TIMEOUT = 300


# ========== SGLang Client ==========
class SGLangModel:
    def __init__(self, url=SGLANG_URL):
        self.url = url

    def call_llm(self, text_prompt: str, image_data_url: str, temp: float = TEMP) -> Dict[str, Any]:
        payload = {
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {"type": "image_url", "image_url": {"url": image_data_url}},
                        {"type": "text", "text": text_prompt},
                    ],
                }
            ],
            "temperature": temp,
            "enable_thinking": False,
        }
        resp = requests.post(self.url, json=payload, timeout=TIMEOUT)
        resp.raise_for_status()
        return resp.json()


# ========== Utils ==========
def iter_jsonl(path: Path):
    with path.open("r", encoding="utf-8") as f:
        for ln, line in enumerate(f, start=1):
            line = line.strip()
            if not line:
                continue
            try:
                yield ln, json.loads(line)
            except Exception as e:
                raise RuntimeError(f"Bad JSON at line {ln}: {e}\n{line[:500]}")


def get_caption(item: dict) -> str:
    return (
        item.get("score_res", {})
        .get("metric_info_image_caption", {})
        .get("response", "")
    ).strip()


def get_domain(item: dict) -> str:
    domain = (
        item.get("score_res", {})
        .get("first_round_theme_metric_info", {})
        .get("predicion_label", "")
    ).strip()
    if domain:
        return domain
    return (item.get("category") or item.get("type") or "Unknown").strip()


def get_image_abs_path(item: dict) -> Path:
    rel = (item.get("image_rel_path") or "").strip()
    if not rel:
        raise KeyError("Missing field: image_rel_path")
    rel = rel.lstrip("/")
    return IMAGE_ROOT / rel


def guess_mime_type(path: Path) -> str:
    mt, _ = mimetypes.guess_type(str(path))
    return mt or "image/png"


def image_to_data_url_base64(image_path: Path) -> str:
    if not image_path.exists():
        raise FileNotFoundError(f"Image not found: {image_path}")
    mime = guess_mime_type(image_path)
    b64 = base64.b64encode(image_path.read_bytes()).decode("utf-8")
    return f"data:{mime};base64,{b64}"


def fill_template(template_text: str, item: dict, image_path: Path) -> str:
    t = Template(template_text)
    # 你模板里如果用到这些变量就会替换；没用到也不影响
    return t.safe_substitute(
        DOMAIN=get_domain(item),
        CAPTION=get_caption(item),
        IMAGE_PATH=str(image_path),
    )


def extract_assistant_text(resp_json: Dict[str, Any]) -> str:
    """
    假设 OpenAI 兼容：choices[0].message.content 是模型输出文本（应为你的 JSON 字符串）
    """
    try:
        return resp_json["choices"][0]["message"]["content"]
    except Exception:
        return json.dumps(resp_json, ensure_ascii=False)


def parse_model_json_text(text: str) -> Optional[dict]:
    """
    你的模型应输出一个 JSON 对象；这里尽量 parse。
    若模型会输出 ```json ...```，也做一次简单清理。
    """
    s = text.strip()
    if s.startswith("```"):
        # 去掉 ```json / ``` 包裹
        s = s.strip("`")
        # 可能形如 "json\n{...}"
        if "\n" in s:
            s = s.split("\n", 1)[1].strip()
    try:
        return json.loads(s)
    except Exception:
        return None


def main():
    template_text = PROMPT_PATH.read_text(encoding="utf-8")
    model = SGLangModel()

    outputs: List[Dict[str, Any]] = []

    for ln, item in iter_jsonl(JSONL_PATH):
        image_path = get_image_abs_path(item)
        image_data_url = image_to_data_url_base64(image_path)
        prompt = fill_template(template_text, item, image_path)

        resp = model.call_llm(text_prompt=prompt, image_data_url=image_data_url, temp=TEMP)
        assistant_text = extract_assistant_text(resp)
        assistant_json = parse_model_json_text(assistant_text)

        outputs.append(
            {
                "source": {
                    "jsonl_path": str(JSONL_PATH),
                    "line_no": ln,
                },
                "meta": {
                    "domain": get_domain(item),
                    "caption_raw": get_caption(item),
                    "image_rel_path": item.get("image_rel_path", ""),
                    "image_abs_path": str(image_path),
                },
                "prompt": prompt,
                "assistant_text": assistant_text,
                "assistant_json": assistant_json,  # parse 成功则是 dict，否则 None
                "raw_item": item,  # 如果你不想存原始输入，可删
            }
        )

        # 可选：边跑边落盘，避免中途崩掉丢数据
        OUT_JSON_PATH.write_text(json.dumps(outputs, ensure_ascii=False, indent=2), encoding="utf-8")

    print(f"Saved {len(outputs)} records to {OUT_JSON_PATH}")


if __name__ == "__main__":
    main()
```

产物 `sglang_outputs.json` 里每条会包含：
- `assistant_text`：模型原始输出文本
- `assistant_json`：能 parse 成 dict 的版本（就是你给的 question/summary/... 那套结构），parse 失败就是 `null`


