import json
from pathlib import Path
from typing import Any, Dict, List, Optional
from PIL import Image

IN_JSON_PATH = Path("sglang_outputs.json")
OUT_JSON_PATH = Path("multimodal_messages.json")


def safe_open_image_wh(image_path: str) -> Optional[List[int]]:
    """
    返回 [w, h]；拿不到则返回 None
    """
    try:
        with Image.open(image_path) as im:
            return [int(im.width), int(im.height)]
    except Exception:
        return None


def main():
    data: List[Dict[str, Any]] = json.loads(IN_JSON_PATH.read_text(encoding="utf-8"))

    out: List[Dict[str, Any]] = []

    for i, rec in enumerate(data):
        meta = rec.get("meta", {})
        src = rec.get("source", {})
        assistant = rec.get("assistant_json")  # 期望是 dict: question/answer/...
        if not isinstance(assistant, dict):
            # 没 parse 成功就跳过或保留占位
            continue

        image_abs_path = meta.get("image_abs_path", "")
        wh = safe_open_image_wh(image_abs_path)

        # 你希望 "<IMG_CONTEXT>\nquestion text"
        # question text 用 assistant["question"]
        question_text = assistant.get("question", "").strip()
        user_text = "<IMG_CONTEXT>\n" + question_text

        # assistant content 放“answer”（你示例里是 answer）
        answer_text = str(assistant.get("answer", "")).strip()

        doc_loc = src.get("jsonl_path", "")  # 你给的示例是 s3://...，这里先用本地 jsonl path
        # 如果你 raw_item 里有真正的 s3 doc_loc 字段，可在这里替换：
        # doc_loc = rec.get("raw_item", {}).get("doc_loc") or doc_loc

        out.append(
            {
                "id": i,
                "messages": [
                    {
                        "role": "user",
                        "content": [
                            {
                                "type": "image_url",
                                "image_url": {
                                    "url": image_abs_path,  # 这里按示例写 "image.jpg"；你也可以写 base64 data url
                                    **({"image_wh": wh} if wh else {}),
                                },
                            },
                            {"type": "text", "text": user_text},
                        ],
                    },
                    {"role": "assistant", "content": answer_text},
                ],
                "doc_loc": doc_loc,
            }
        )

    OUT_JSON_PATH.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"Wrote {len(out)} records to {OUT_JSON_PATH}")


if __name__ == "__main__":
    main()
